export default {
  "styles": ":root{\n  --bg:#044152;\n  --card:#092e37;\n  --cardAlt:#0d3944;\n  --muted:#a2ebf3;\n  --text:#ebf2f2;\n  --accent:#58dbed;\n  --accentSoft:rgba(88,219,237,.18);\n  --stroke:#0e2230;\n  --chip:#12343e;\n  --chipBorder:#174550;\n  --ink:#1f2121;\n  --danger:#ff8261;\n  --dangerBorder:#7b1d1d;\n}\n*{box-sizing:border-box}\nbody{margin:0;background:var(--bg);color:var(--text);font:14px/1.45 Inter,system-ui,Segoe UI,Roboto,Helvetica,Arial,sans-serif}\n.wrap{max-width:1440px;margin:0 auto;padding:20px}\nh1,h2,h3{margin:0}\np{margin:0}\n.muted{color:var(--muted)}\n.card{background:var(--card);border:1px solid var(--stroke);border-radius:14px;padding:16px}\n.page-head{display:flex;align-items:flex-end;justify-content:space-between;gap:16px;margin-bottom:16px}\n.page-head p{max-width:860px}\n.controls{display:flex;flex-direction:column;gap:12px;margin-bottom:16px}\n.controls-grid{display:grid;grid-template-columns:220px minmax(260px,420px) auto;gap:12px;align-items:end}\n.field-label{font-size:12px;padding-left:8px;color:var(--muted);display:block;margin-bottom:6px}\nselect,button{height:36px;border-radius:10px;border:1px solid #23314d;background:var(--ink);color:var(--text);padding:8px 12px;font:inherit}\nbutton{cursor:pointer}\nbutton:hover{filter:brightness(1.08)}\n.lookback-controls{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:8px}\n.lookback-btn{font-weight:600}\n.lookback-btn.active{border-color:var(--accent);box-shadow:0 0 0 1px rgba(88,219,237,.35);color:var(--accent)}\n.status-line{font-size:12px;min-height:18px}\n.status-line.error{color:var(--danger)}\n.stats-grid{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:12px;margin-bottom:16px}\n.stat-card{background:var(--cardAlt);border:1px solid var(--stroke);border-radius:12px;padding:14px}\n.stat-card .label{display:block;font-size:12px;color:var(--muted);margin-bottom:8px}\n.stat-card strong{font-size:24px;line-height:1}\n.stack{display:flex;flex-direction:column;gap:16px}\n.section-head{display:flex;align-items:flex-start;justify-content:space-between;gap:12px;margin-bottom:12px}\n.section-head p{max-width:720px}\n.detail-controls{min-width:260px}\n.detail-controls select{width:100%}\n.subsection-head{display:flex;align-items:flex-start;justify-content:space-between;gap:12px;margin:18px 0 10px}\n.table-scroll{overflow:auto;-webkit-overflow-scrolling:touch}\n.table-scroll::-webkit-scrollbar{height:8px;width:8px}\n.table-scroll::-webkit-scrollbar-track{background:rgba(255,255,255,.05);border-radius:999px}\n.table-scroll::-webkit-scrollbar-thumb{background:rgba(255,255,255,.16);border-radius:999px}\ntable{width:100%;border-collapse:separate;border-spacing:0 8px}\nthead th{font-size:11px;font-weight:600;color:var(--muted);text-align:left;padding:0 10px 4px;vertical-align:bottom;white-space:nowrap}\nthead th.numeric{text-align:right}\ntbody td{background:var(--ink);border-top:1px solid #0f1831;border-bottom:1px solid #0f1831;padding:10px;vertical-align:top}\ntbody td.numeric{text-align:right;font-variant-numeric:tabular-nums}\ntbody tr td:first-child{border-left:1px solid #0f1831;border-radius:12px 0 0 12px}\ntbody tr td:last-child{border-right:1px solid #0f1831;border-radius:0 12px 12px 0}\n.table-empty td{text-align:center;color:var(--muted);padding:18px 12px}\n.tag-pill{display:inline-flex;align-items:center;gap:6px;padding:3px 10px;border-radius:999px;border:1px solid var(--dangerBorder);background:rgba(255,130,97,.08);color:#ffd7cd;font-size:12px;font-weight:600}\n.crisis-row{cursor:pointer}\n.crisis-row:hover td{background:#253640}\n.crisis-row.selected td{background:rgba(88,219,237,.12)}\n.crisis-row.selected td:first-child{border-left-color:var(--accent)}\n.crisis-row.selected td:last-child{border-right-color:var(--accent)}\n.detail-shell{display:flex;flex-direction:column;gap:14px}\n.detail-empty{padding:28px 20px;border:1px dashed rgba(162,235,243,.28);border-radius:12px;color:var(--muted);text-align:center}\n.detail-summary{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px}\n.detail-mini{background:var(--cardAlt);border:1px solid var(--stroke);border-radius:12px;padding:12px}\n.detail-mini .label{display:block;font-size:12px;color:var(--muted);margin-bottom:6px}\n.detail-mini strong{font-size:20px;line-height:1}\n.table-block{display:flex;flex-direction:column;gap:10px}\n.table-block h3{font-size:15px}\n.brand-name{font-weight:600}\n.yes-pill,.no-pill{display:inline-flex;align-items:center;padding:3px 8px;border-radius:999px;font-size:12px;border:1px solid transparent}\n.yes-pill{background:rgba(88,219,237,.14);border-color:rgba(88,219,237,.35);color:var(--accent)}\n.no-pill{background:rgba(255,255,255,.05);border-color:rgba(255,255,255,.12);color:var(--muted)}\n.trend-chart-shell{position:relative;min-height:340px;height:42vh;max-height:520px}\n.trend-chart-shell canvas{width:100% !important;height:100% !important;display:block}\n.chart-empty{position:absolute;inset:0;display:flex;align-items:center;justify-content:center;border:1px dashed rgba(162,235,243,.28);border-radius:12px;color:var(--muted);background:rgba(0,0,0,.08)}\n@media (max-width: 900px){\n  .controls-grid{grid-template-columns:1fr}\n  .stats-grid{grid-template-columns:repeat(2,minmax(0,1fr))}\n  .detail-summary{grid-template-columns:repeat(2,minmax(0,1fr))}\n  .section-head,.subsection-head{flex-direction:column}\n  .detail-controls{min-width:0;width:100%}\n}\n@media (max-width: 620px){\n  .wrap{padding:16px}\n  .stats-grid{grid-template-columns:1fr}\n  .detail-summary{grid-template-columns:1fr}\n}",
  "markup": "<div class=\"wrap\">\n  <header class=\"page-head\">\n    <div>\n      <h1>Crisis Dashboard: Crises</h1>\n      <p class=\"muted\">Track which crisis categories are expanding, which are still active, and which brands are carrying each category in the selected window.</p>\n    </div>\n  </header>\n\n  <section class=\"card controls\">\n    <div class=\"controls-grid\">\n      <div>\n        <label class=\"field-label\" for=\"dateSelect\">Window End Date</label>\n        <select id=\"dateSelect\"></select>\n      </div>\n      <div>\n        <span class=\"field-label\">Lookback Window</span>\n        <div class=\"lookback-controls\" role=\"group\" aria-label=\"Lookback window\">\n          <button type=\"button\" class=\"lookback-btn\" data-days=\"30\">30d</button>\n          <button type=\"button\" class=\"lookback-btn\" data-days=\"45\">45d</button>\n          <button type=\"button\" class=\"lookback-btn\" data-days=\"60\">60d</button>\n          <button type=\"button\" class=\"lookback-btn\" data-days=\"90\">90d</button>\n        </div>\n      </div>\n      <div class=\"muted\">\n        Crisis rows come from tagged daily crisis events and recent negative coverage in the selected window.\n      </div>\n    </div>\n    <div id=\"statusLine\" class=\"status-line muted\"></div>\n  </section>\n\n  <section class=\"stats-grid\">\n    <div class=\"stat-card\">\n      <span class=\"label\">Crises In Window</span>\n      <strong id=\"statCrisisCount\">0</strong>\n    </div>\n    <div class=\"stat-card\">\n      <span class=\"label\">Distinct Brands Affected</span>\n      <strong id=\"statBrandCount\">0</strong>\n    </div>\n    <div class=\"stat-card\">\n      <span class=\"label\">Active Brands</span>\n      <strong id=\"statActiveBrandCount\">0</strong>\n    </div>\n    <div class=\"stat-card\">\n      <span class=\"label\">Average Crisis Length</span>\n      <strong id=\"statAvgCrisisLength\">0d</strong>\n    </div>\n    <div class=\"stat-card\">\n      <span class=\"label\">Brand-Days</span>\n      <strong id=\"statBrandDays\">0</strong>\n    </div>\n  </section>\n\n  <section class=\"stack\">\n    <div class=\"card\">\n      <div class=\"section-head\">\n        <div>\n          <h2>Crisis Summary</h2>\n          <p class=\"muted\">Click a crisis category to update the selector and focus the detail panel below.</p>\n        </div>\n      </div>\n      <div class=\"table-scroll\">\n        <table>\n          <thead>\n            <tr>\n              <th>Crisis Type</th>\n              <th class=\"numeric\">Affected Brands</th>\n              <th class=\"numeric\">Active Brands</th>\n              <th class=\"numeric\">Average Active Days</th>\n              <th class=\"numeric\">Longest Active Days</th>\n            </tr>\n          </thead>\n          <tbody id=\"summaryBody\"></tbody>\n        </table>\n      </div>\n    </div>\n\n    <div class=\"card\">\n      <div class=\"section-head\">\n        <div>\n          <h2>Crisis Trends</h2>\n          <p class=\"muted\">Daily active-brand counts for the most visible crisis categories in the selected window. The chart highlights the leading categories; the table shows the latest dates in the same window.</p>\n        </div>\n      </div>\n      <div class=\"trend-chart-shell\">\n        <canvas id=\"trendChart\"></canvas>\n        <div id=\"trendChartEmpty\" class=\"chart-empty\" hidden>Trend data will appear here when crisis categories are available.</div>\n      </div>\n\n      <div class=\"subsection-head\">\n        <div>\n          <h3>Trend Table</h3>\n          <p id=\"trendTableNote\" class=\"muted\"></p>\n        </div>\n      </div>\n      <div class=\"table-scroll\">\n        <table>\n          <thead id=\"trendHead\"></thead>\n          <tbody id=\"trendBody\"></tbody>\n        </table>\n      </div>\n    </div>\n\n    <div class=\"card\">\n      <div class=\"section-head\">\n        <div>\n          <h2 id=\"detailHeading\">Selected Crisis</h2>\n          <p id=\"detailSubhead\" class=\"muted\">Choose a crisis from the summary table to see the brands carrying it in the current window.</p>\n        </div>\n        <div class=\"detail-controls\">\n          <label class=\"field-label\" for=\"crisisSelect\">Selected Crisis</label>\n          <select id=\"crisisSelect\" disabled>\n            <option value=\"\">Select a crisis</option>\n          </select>\n        </div>\n      </div>\n\n      <div id=\"detailEmpty\" class=\"detail-empty\">No crisis is selected for this window yet.</div>\n\n      <div id=\"detailContent\" class=\"detail-shell\" hidden>\n        <div class=\"detail-summary\">\n          <div class=\"detail-mini\">\n            <span class=\"label\">Brands Affected</span>\n            <strong id=\"detailBrandCount\">0</strong>\n          </div>\n          <div class=\"detail-mini\">\n            <span class=\"label\">Active Brands</span>\n            <strong id=\"detailActiveCount\">0</strong>\n          </div>\n          <div class=\"detail-mini\">\n            <span class=\"label\">Average Active Days</span>\n            <strong id=\"detailAvgActiveDays\">0d</strong>\n          </div>\n          <div class=\"detail-mini\">\n            <span class=\"label\">Longest Active Days</span>\n            <strong id=\"detailLongestActiveDays\">0d</strong>\n          </div>\n        </div>\n\n        <div class=\"table-block\">\n          <h3>Affected Brands</h3>\n          <div class=\"table-scroll\">\n            <table>\n              <thead>\n                <tr>\n                  <th>Brand</th>\n                  <th>Sector</th>\n                  <th class=\"numeric\">Active Days</th>\n                  <th>First Seen</th>\n                  <th>Last Seen</th>\n                  <th>Still Active?</th>\n                </tr>\n              </thead>\n              <tbody id=\"brandBody\"></tbody>\n            </table>\n          </div>\n        </div>\n      </div>\n    </div>\n  </section>\n</div>",
  "externalScripts": [
    "https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js",
    "/static/app/shared-data.js"
  ],
  "inlineScript": "const LOOKBACK_OPTIONS = [30, 45, 60, 90];\nconst TREND_COLORS = ['#ff3b30', '#ff6b57', '#f59e0b', '#facc15', '#d1d5db', '#bfdbfe', '#22c55e', '#a78bfa'];\nconst MAX_TREND_SERIES = 6;\nconst TREND_TABLE_DAYS = 7;\n\nconst params = new URLSearchParams(window.location.search);\nconst requestedDays = Number(params.get('days') || '');\nlet currentDays = LOOKBACK_OPTIONS.includes(requestedDays) ? requestedDays : 30;\nlet selectedCrisisTag = (params.get('crisis_tag') || '').trim();\nlet availableDates = [];\nlet activeRequestToken = 0;\nlet trendChart = null;\n\nconst esc = (value) => String(value ?? '').replace(/[&<>\\\"']/g, (match) => ({\n  '&': '&amp;',\n  '<': '&lt;',\n  '>': '&gt;',\n  '\"': '&quot;',\n  \"'\": '&#39;',\n}[match]));\n\nfunction setStatus(message, isError = false){\n  const node = document.getElementById('statusLine');\n  node.textContent = message || '';\n  node.classList.toggle('error', !!isError);\n}\n\nfunction syncLookbackButtons(){\n  document.querySelectorAll('.lookback-btn').forEach((button) => {\n    button.classList.toggle('active', Number(button.dataset.days) === currentDays);\n  });\n}\n\nfunction buildStartDate(endIso, days){\n  const end = new Date(`${endIso}T00:00:00Z`);\n  end.setUTCDate(end.getUTCDate() - (days - 1));\n  return end.toISOString().slice(0, 10);\n}\n\nconst _jsonCache = new Map();\nasync function fetchJson(url){\n  const sharedData = window.CrisisDashboardData;\n  if (sharedData?.fetchJson) {\n    return sharedData.fetchJson(url);\n  }\n  if (_jsonCache.has(url)) {\n    const cached = _jsonCache.get(url);\n    return cached instanceof Promise ? await cached : cached;\n  }\n  const pending = (async () => {\n    const response = await fetch(url, { cache: 'default' });\n    if (!response.ok){\n      let detail = `HTTP ${response.status}`;\n      try {\n        const payload = await response.json();\n        if (payload && payload.error) detail = payload.error;\n      } catch (_err) {\n        // Ignore JSON parse failures for error bodies.\n      }\n      throw new Error(detail);\n    }\n    return await response.json();\n  })();\n  _jsonCache.set(url, pending);\n  try {\n    const data = await pending;\n    _jsonCache.set(url, data);\n    return data;\n  } catch (error) {\n    _jsonCache.delete(url);\n    throw error;\n  }\n}\n\nfunction renderActivePill(isActive){\n  return isActive\n    ? '<span class=\"yes-pill\">Active</span>'\n    : '<span class=\"no-pill\">Inactive</span>';\n}\n\nfunction fmtDays(value){\n  const num = Number(value || 0);\n  if (!Number.isFinite(num) || num <= 0) return '0d';\n  const rounded = Math.round(num * 10) / 10;\n  return `${Number.isInteger(rounded) ? rounded.toFixed(0) : rounded.toFixed(1)}d`;\n}\n\nfunction shortDateLabel(isoDate, includeYear = false){\n  const parts = String(isoDate || '').split('-');\n  if (parts.length !== 3) return String(isoDate || '');\n  const month = Number(parts[1]);\n  const day = Number(parts[2]);\n  if (includeYear) return `${month}/${day}/${parts[0].slice(2)}`;\n  return `${month}/${day}`;\n}\n\nfunction updateSummaryStats(payload){\n  const rows = Array.isArray(payload.crises) ? payload.crises : [];\n  const avgCrisisLength = rows.length\n    ? rows.reduce((sum, row) => sum + Number(row.avg_active_days || 0), 0) / rows.length\n    : 0;\n  document.getElementById('statCrisisCount').textContent = String(payload.crisis_count || 0);\n  document.getElementById('statBrandCount').textContent = String(payload.affected_brand_count || 0);\n  document.getElementById('statActiveBrandCount').textContent = String(payload.active_brand_count || 0);\n  document.getElementById('statAvgCrisisLength').textContent = fmtDays(avgCrisisLength);\n  document.getElementById('statBrandDays').textContent = String(payload.brand_day_count || 0);\n}\n\nfunction renderSummaryTable(payload){\n  const tbody = document.getElementById('summaryBody');\n  const rows = Array.isArray(payload.crises) ? payload.crises : [];\n  if (!rows.length){\n    tbody.innerHTML = '<tr class=\"table-empty\"><td colspan=\"5\">No crisis tags were active in this window.</td></tr>';\n    return;\n  }\n\n  const selectedKey = ((payload.selected_crisis && payload.selected_crisis.tag) || selectedCrisisTag || '').toLowerCase();\n  tbody.innerHTML = rows.map((row) => {\n    const isSelected = String(row.tag || '').toLowerCase() === selectedKey;\n    return `<tr class=\"crisis-row${isSelected ? ' selected' : ''}\" data-crisis-tag=\"${esc(row.tag)}\">\n      <td><span class=\"tag-pill\">${esc(row.display_tag || row.tag || '')}</span></td>\n      <td class=\"numeric\">${row.brands_affected || 0}</td>\n      <td class=\"numeric\">${row.active_brands_latest || 0}</td>\n      <td class=\"numeric\">${fmtDays(row.avg_active_days || 0)}</td>\n      <td class=\"numeric\">${fmtDays(row.longest_active_days || 0)}</td>\n    </tr>`;\n  }).join('');\n\n  tbody.querySelectorAll('[data-crisis-tag]').forEach((row) => {\n    row.addEventListener('click', () => {\n      selectedCrisisTag = String(row.getAttribute('data-crisis-tag') || '').trim();\n      loadCrisisWindow();\n    });\n  });\n}\n\nfunction renderCrisisSelect(payload){\n  const select = document.getElementById('crisisSelect');\n  const rows = Array.isArray(payload.crises) ? payload.crises : [];\n  const selectedTag = (payload.selected_crisis && payload.selected_crisis.tag) || selectedCrisisTag || '';\n\n  if (!rows.length){\n    select.innerHTML = '<option value=\"\">Select a crisis</option>';\n    select.disabled = true;\n    return;\n  }\n\n  select.disabled = false;\n  select.innerHTML = rows.map((row) => (\n    `<option value=\"${esc(row.tag)}\">${esc(row.display_tag || row.tag || '')}</option>`\n  )).join('');\n  if (selectedTag) select.value = selectedTag;\n}\n\nfunction renderSelectedCrisis(payload){\n  const detailHeading = document.getElementById('detailHeading');\n  const detailSubhead = document.getElementById('detailSubhead');\n  const detailEmpty = document.getElementById('detailEmpty');\n  const detailContent = document.getElementById('detailContent');\n  const selected = payload.selected_crisis;\n\n  renderCrisisSelect(payload);\n\n  if (!selected){\n    detailHeading.textContent = 'Selected Crisis';\n    detailSubhead.textContent = 'Choose a crisis from the summary table to see the brands carrying it in the current window.';\n    detailEmpty.hidden = false;\n    detailContent.hidden = true;\n    document.getElementById('brandBody').innerHTML = '';\n    return;\n  }\n\n  detailEmpty.hidden = true;\n  detailContent.hidden = false;\n  detailHeading.textContent = selected.display_tag || selected.tag || 'Selected crisis';\n  detailSubhead.textContent = `Visible on ${selected.crisis_days || 0} dates in the selected window, with ${selected.total_negative_items || 0} tagged negative items behind the crisis signal.`;\n  document.getElementById('detailBrandCount').textContent = String(selected.brands_affected || 0);\n  document.getElementById('detailActiveCount').textContent = String(selected.active_brands_latest || 0);\n  document.getElementById('detailAvgActiveDays').textContent = fmtDays(selected.avg_active_days || 0);\n  document.getElementById('detailLongestActiveDays').textContent = fmtDays(selected.longest_active_days || 0);\n\n  const brandBody = document.getElementById('brandBody');\n  const brands = Array.isArray(selected.brands) ? selected.brands : [];\n  if (!brands.length){\n    brandBody.innerHTML = '<tr class=\"table-empty\"><td colspan=\"6\">No brands were attached to this crisis in the selected window.</td></tr>';\n    return;\n  }\n\n  brandBody.innerHTML = brands.map((brand) => `<tr>\n    <td><span class=\"brand-name\">${esc(brand.brand || '')}</span></td>\n    <td>${esc(brand.sector || 'Unassigned')}</td>\n    <td class=\"numeric\">${brand.days_affected || 0}</td>\n    <td>${esc(brand.first_seen_date || '')}</td>\n    <td>${esc(brand.last_seen_date || '')}</td>\n    <td>${renderActivePill(!!brand.active_on_window_end)}</td>\n  </tr>`).join('');\n}\n\nfunction selectTrendRowsForChart(payload){\n  const rows = Array.isArray(payload.trend_rows) ? payload.trend_rows : [];\n  const selectedKey = ((payload.selected_crisis && payload.selected_crisis.tag) || selectedCrisisTag || '').toLowerCase();\n  const selectedRow = rows.find((row) => String(row.tag || '').toLowerCase() === selectedKey);\n  let visibleRows = rows.slice(0, MAX_TREND_SERIES);\n  if (selectedRow && !visibleRows.some((row) => String(row.tag || '').toLowerCase() === selectedKey)){\n    visibleRows = visibleRows.slice(0, Math.max(0, MAX_TREND_SERIES - 1));\n    visibleRows.push(selectedRow);\n  }\n  return visibleRows;\n}\n\nfunction destroyTrendChart(){\n  if (trendChart){\n    trendChart.destroy();\n    trendChart = null;\n  }\n}\n\nfunction renderTrendChart(payload){\n  const dates = Array.isArray(payload.trend_dates) ? payload.trend_dates : [];\n  const rows = selectTrendRowsForChart(payload);\n  const canvas = document.getElementById('trendChart');\n  const empty = document.getElementById('trendChartEmpty');\n\n  destroyTrendChart();\n\n  if (!dates.length || !rows.length){\n    canvas.hidden = true;\n    empty.hidden = false;\n    return;\n  }\n\n  canvas.hidden = false;\n  empty.hidden = true;\n\n  trendChart = new Chart(canvas.getContext('2d'), {\n    type: 'line',\n    data: {\n      labels: dates.map((dateValue) => shortDateLabel(dateValue)),\n      datasets: rows.map((row, index) => {\n        const color = TREND_COLORS[index % TREND_COLORS.length];\n        return {\n          label: row.display_tag || row.tag || `Crisis ${index + 1}`,\n          data: Array.isArray(row.active_brands_series) ? row.active_brands_series : [],\n          borderColor: color,\n          backgroundColor: color,\n          pointRadius: 0,\n          pointHoverRadius: 4,\n          borderWidth: 3,\n          tension: 0.24,\n        };\n      }),\n    },\n    options: {\n      responsive: true,\n      maintainAspectRatio: false,\n      interaction: {\n        mode: 'index',\n        intersect: false,\n      },\n      plugins: {\n        legend: {\n          position: 'right',\n          labels: {\n            color: '#ebf2f2',\n            boxWidth: 14,\n            boxHeight: 3,\n            usePointStyle: false,\n          },\n        },\n        tooltip: {\n          callbacks: {\n            title: (items) => {\n              const idx = items?.[0]?.dataIndex ?? 0;\n              return dates[idx] || '';\n            },\n            label: (context) => {\n              const label = context.dataset?.label || 'Series';\n              return `${label}: ${context.parsed?.y ?? 0}`;\n            },\n          },\n        },\n      },\n      scales: {\n        x: {\n          ticks: {\n            color: '#ebf2f2',\n            maxTicksLimit: 10,\n          },\n          grid: {\n            color: 'rgba(255,255,255,.08)',\n          },\n        },\n        y: {\n          beginAtZero: true,\n          ticks: {\n            color: '#ebf2f2',\n          },\n          grid: {\n            color: 'rgba(255,255,255,.08)',\n          },\n        },\n      },\n    },\n  });\n}\n\nfunction renderTrendTable(payload){\n  const head = document.getElementById('trendHead');\n  const body = document.getElementById('trendBody');\n  const note = document.getElementById('trendTableNote');\n  const dates = Array.isArray(payload.trend_dates) ? payload.trend_dates : [];\n  const rows = Array.isArray(payload.trend_rows) ? payload.trend_rows : [];\n\n  if (!dates.length || !rows.length){\n    head.innerHTML = '';\n    body.innerHTML = '<tr class=\"table-empty\"><td colspan=\"2\">No trend rows are available for this window.</td></tr>';\n    note.textContent = '';\n    return;\n  }\n\n  const visibleCount = Math.min(TREND_TABLE_DAYS, dates.length);\n  const visibleDates = dates.slice(-visibleCount);\n  note.textContent = `Showing the last ${visibleCount} date${visibleCount === 1 ? '' : 's'} in the selected window.`;\n\n  head.innerHTML = `<tr>\n    <th>Crisis Type</th>\n    ${visibleDates.map((dateValue) => `<th class=\"numeric\" title=\"${esc(dateValue)}\">${esc(shortDateLabel(dateValue, true))}</th>`).join('')}\n  </tr>`;\n\n  body.innerHTML = rows.map((row) => {\n    const series = Array.isArray(row.active_brands_series) ? row.active_brands_series.slice(-visibleCount) : [];\n    return `<tr>\n      <td><span class=\"tag-pill\">${esc(row.display_tag || row.tag || '')}</span></td>\n      ${series.map((value) => `<td class=\"numeric\">${value || 0}</td>`).join('')}\n    </tr>`;\n  }).join('');\n}\n\nasync function loadAvailableDates(){\n  const payload = await fetchJson('/api/dates');\n  availableDates = Array.isArray(payload.dates) ? payload.dates : [];\n  const select = document.getElementById('dateSelect');\n  const requestedDate = (params.get('date') || '').trim();\n  const initialDate = availableDates.includes(requestedDate) ? requestedDate : (availableDates[0] || '');\n  select.innerHTML = availableDates.map((dateValue) => (\n    `<option value=\"${esc(dateValue)}\">${esc(dateValue)}</option>`\n  )).join('');\n  if (initialDate) select.value = initialDate;\n}\n\nasync function loadCrisisWindow(){\n  const requestToken = ++activeRequestToken;\n  const endDate = (document.getElementById('dateSelect').value || '').trim();\n  const emptyPayload = {\n    crisis_count: 0,\n    affected_brand_count: 0,\n    active_brand_count: 0,\n    brand_day_count: 0,\n    crises: [],\n    trend_dates: [],\n    trend_rows: [],\n    selected_crisis: null,\n  };\n\n  if (!endDate){\n    updateSummaryStats(emptyPayload);\n    renderSummaryTable(emptyPayload);\n    renderTrendChart(emptyPayload);\n    renderTrendTable(emptyPayload);\n    renderSelectedCrisis(emptyPayload);\n    setStatus('No dates are available yet.');\n    return;\n  }\n\n  const startDate = buildStartDate(endDate, currentDays);\n  const query = new URLSearchParams({\n    start_date: startDate,\n    end_date: endDate,\n  });\n  if (selectedCrisisTag) query.set('crisis_tag', selectedCrisisTag);\n\n  setStatus(`Loading crisis activity for ${startDate} to ${endDate}...`);\n  try {\n    const payload = await fetchJson(`/api/v1/insights/crisis_brand_impact?${query.toString()}`);\n    if (requestToken !== activeRequestToken) return;\n    if (!payload.selected_crisis && selectedCrisisTag){\n      selectedCrisisTag = '';\n    } else if (payload.selected_crisis && payload.selected_crisis.tag){\n      selectedCrisisTag = payload.selected_crisis.tag;\n    }\n    updateSummaryStats(payload);\n    renderSummaryTable(payload);\n    renderTrendChart(payload);\n    renderTrendTable(payload);\n    renderSelectedCrisis(payload);\n    setStatus(`Showing crisis activity from ${payload.window_start} to ${payload.window_end}.`);\n  } catch (error) {\n    if (requestToken !== activeRequestToken) return;\n    updateSummaryStats(emptyPayload);\n    renderSummaryTable(emptyPayload);\n    renderTrendChart(emptyPayload);\n    renderTrendTable(emptyPayload);\n    renderSelectedCrisis(emptyPayload);\n    setStatus(`Unable to load crisis activity: ${error.message}`, true);\n  }\n}\n\nfunction bindControls(){\n  const dateSelect = document.getElementById('dateSelect');\n  dateSelect.addEventListener('change', () => {\n    loadCrisisWindow();\n  });\n\n  const crisisSelect = document.getElementById('crisisSelect');\n  crisisSelect.addEventListener('change', () => {\n    selectedCrisisTag = String(crisisSelect.value || '').trim();\n    loadCrisisWindow();\n  });\n\n  document.querySelectorAll('.lookback-btn').forEach((button) => {\n    button.addEventListener('click', () => {\n      const nextDays = Number(button.dataset.days || 0);\n      if (!LOOKBACK_OPTIONS.includes(nextDays) || nextDays === currentDays) return;\n      currentDays = nextDays;\n      syncLookbackButtons();\n      loadCrisisWindow();\n    });\n  });\n}\n\nasync function init(){\n  syncLookbackButtons();\n  bindControls();\n  try {\n    await loadAvailableDates();\n  } catch (error) {\n    setStatus(`Unable to load available dates: ${error.message}`, true);\n    return;\n  }\n  await loadCrisisWindow();\n}\n\nwindow.addEventListener('beforeunload', destroyTrendChart);\ninit();"
};
